        int u = dq.front();
        dq.pop_front();

        if (u == target) {
            // Optimization: if we reached target, we found the shortest path in terms of heavy edges
            // If this path is already too long, further exploration might not help for this specific path,
            // but 0-1 BFS guarantees the first time we extract target it's the shortest path.
            // However, we continue to ensure all distances are correctly minimized.
