            if (dist[u] != LLONG_MAX && dist[u] + cost < dist[v]) {
                dist[v] = dist[u] + cost;

                if (cost == 0) {
                    dq.push_front(v);
                } else {
                    dq.push_back(v);
                }
            }
        }
    }

    return dist[target] <= k;
