type State = struct {
    u: int64
    c: int64
}

// Function to check if a valid path exists for a given threshold T
func canReach(n: int64, adj: [][]Edge, source: int64, target: int64, k: int64, T: int64) bool {
    if source == target {
        return true
    }

    // D[u][c] stores whether node u is reachable using exactly c heavy edges.
    // Since N and K are up to 1000, we use a 2D boolean array.
    // N is int64, K is int64, but we cast them to int for array indexing if necessary, 
    // assuming N <= 1000 fits in standard int.

    N_int := int(n)
    K_int := int(k)

    // Initialize reachability matrix: reachable[node][heavy_count]
    reachable := make([][]bool, N_int)
    for i := range reachable {
        reachable[i] = make([]bool, K_int + 1)
    }

    // Queue for BFS
    queue := make([]State, 0)

    // Start state
    reachable[source] = true[0]
    queue = append(queue, State{u: source, c: 0})

    head := 0
    for head < len(queue) {
        curr := queue[head]
        head++
        u := curr.u
        c := curr.c

        if u == target {
            // Reached target within the constraint K
            return true
        }

        for _, edge := range adj[u] {
            v := edge.v
            w := edge.w

            // Determine if the edge is heavy
            isHeavy := w > T

            c_new := c + (isHeavy ? 1 : 0)

            if c_new <= k {
                v_int := int(v)
                c_new_int := int(c_new)

                if !reachable[v_int][c_new_int] {
                    reachable[v_int][c_new_int] = true
                    queue = append(queue, State{u: v, c: c_new})
                }
            }
        }
    }

    // After BFS, check if target was reached with any count <= K
    // This check is technically redundant if we check inside the loop when u == target, 
    // but serves as a final safety check.
    target_int := int(target)
    for c_int := 0; c_int <= K_int; c_int++ {
        if reachable[target_int][c_int] {
            return true
        }
    }

    return false
}

