        // Undirected graph
        adj[u] = append(adj[u], Edge{v: v, w: w})
        adj[v] = append(adj[v], Edge{v: u, w: w})
    }

    // 2. Binary Search on Threshold T
    // Search space: [0, 10^9 + 1]. 
    // Max possible weight is 10^9. If T = 10^9, all edges are light or equal to max weight.
    L := int64(0)
    R := int64(1e9) + 2 // Upper bound slightly larger than max possible weight

    result := int64(-1)

    // We search for the minimum T such that CanReach(T) is true.
    for L < R {
        T_mid := L + (R - L) / 2

        if canReach(n, adj, source, target, k, T_mid) {
